namespace sv_af5af2da9bb2403e9663a3c55eb7a148.Models;

// Immutable records for submission
public record JobApplication(PersonalInfo Personal, WorkHistory Work, List<Reference> References, string CoverLetter);
public record PersonalInfo(string FullName, string Email, string Phone, string Address);
public record WorkHistory(List<WorkEntry> Entries);
public record WorkEntry(string Company, string Title, DateTime StartDate, DateTime? EndDate, string Description);
public record Reference(string Name, string Relationship, string Email, string Phone);

public interface IApplicationService
{
    Task<int> SubmitApplicationAsync(JobApplication application);
    Task<bool> ValidateEmailAsync(string email);
}

// Mutable form models for two-way binding
public class PersonalInfoModel
{
    public string FullName { get; set; } = "";
    public string Email { get; set; } = "";
    public string Phone { get; set; } = "";
    public string Address { get; set; } = "";

    public bool IsValid() =>
        !string.IsNullOrWhiteSpace(FullName) &&
        !string.IsNullOrWhiteSpace(Email) &&
        !string.IsNullOrWhiteSpace(Phone) &&
        !string.IsNullOrWhiteSpace(Address);

    public PersonalInfo ToRecord() => new(FullName.Trim(), Email.Trim(), Phone.Trim(), Address.Trim());
}

public class WorkEntryModel
{
    public string Company { get; set; } = "";
    public string Title { get; set; } = "";
    public DateTime? StartDate { get; set; }
    public DateTime? EndDate { get; set; }
    public bool IsCurrent { get; set; }
    public string Description { get; set; } = "";

    public bool IsValid() =>
        !string.IsNullOrWhiteSpace(Company) &&
        !string.IsNullOrWhiteSpace(Title) &&
        StartDate.HasValue;

    public WorkEntry ToRecord() => new(
        Company.Trim(),
        Title.Trim(),
        StartDate!.Value,
        IsCurrent ? null : EndDate,
        Description.Trim());
}

public class ReferenceModel
{
    public string Name { get; set; } = "";
    public string Relationship { get; set; } = "";
    public string Email { get; set; } = "";
    public string Phone { get; set; } = "";

    public bool IsValid() =>
        !string.IsNullOrWhiteSpace(Name) &&
        !string.IsNullOrWhiteSpace(Relationship) &&
        !string.IsNullOrWhiteSpace(Email) &&
        !string.IsNullOrWhiteSpace(Phone);

    public Reference ToRecord() => new(Name.Trim(), Relationship.Trim(), Email.Trim(), Phone.Trim());
}

@namespace sv_af5af2da9bb2403e9663a3c55eb7a148.Components.Pages.Apply

<nav aria-label="Application progress" class="step-indicator mb-4">
    <ol class="list-unstyled d-flex justify-content-between align-items-center m-0 p-0">
        @for (int i = 0; i < StepNames.Length; i++)
        {
            var stepIndex = i;
            var isCompleted = CompletedSteps.Contains(stepIndex);
            var isCurrent = stepIndex == CurrentStep;
            var cssClass = isCurrent ? "step active" : isCompleted ? "step completed" : "step dimmed";

            <li class="@cssClass text-center flex-fill position-relative">
                @if (isCompleted && !isCurrent)
                {
                    <button class="btn btn-link p-0 text-decoration-none w-100" @onclick="() => OnStepClicked.InvokeAsync(stepIndex)">
                        <span class="step-circle bg-success text-white">✓</span>
                        <span class="step-label d-block small mt-1 text-success">@StepNames[stepIndex]</span>
                    </button>
                }
                else
                {
                    <div>
                        <span class="step-circle @(isCurrent ? "bg-primary text-white" : "bg-secondary text-white")">@(stepIndex + 1)</span>
                        <span class="step-label d-block small mt-1 @(isCurrent ? "fw-bold text-primary" : "text-muted")">@StepNames[stepIndex]</span>
                    </div>
                }
            </li>
        }
    </ol>
</nav>

<style>
    .step-indicator .step-circle {
        display: inline-flex;
        align-items: center;
        justify-content: center;
        width: 36px;
        height: 36px;
        border-radius: 50%;
        font-size: 0.875rem;
        font-weight: 600;
    }

    .step-indicator .step.dimmed {
        opacity: 0.5;
    }

    .step-indicator .step-label {
        font-size: 0.75rem;
    }
</style>

@code {
    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter, EditorRequired] public HashSet<int> CompletedSteps { get; set; } = new();
    [Parameter, EditorRequired] public EventCallback<int> OnStepClicked { get; set; }

    private static readonly string[] StepNames =
        ["Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"];
}

@namespace sv_af5af2da9bb2403e9663a3c55eb7a148.Components.Pages.Apply
@using sv_af5af2da9bb2403e9663a3c55eb7a148.Models

<div class="card mb-3">
    <div class="card-body">
        <div class="d-flex justify-content-between align-items-center mb-3">
            <h6 class="card-title mb-0">Reference @Index</h6>
            @if (CanRemove)
            {
                <button type="button" class="btn btn-outline-danger btn-sm" @onclick="() => OnRemove.InvokeAsync()">Remove</button>
            }
        </div>

        <div class="row g-3">
            <div class="col-md-6">
                <label class="form-label">Name <span class="text-danger">*</span></label>
                <input type="text" class="form-control" @bind="Reference.Name" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Relationship <span class="text-danger">*</span></label>
                <input type="text" class="form-control" @bind="Reference.Relationship" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Email <span class="text-danger">*</span></label>
                <input type="email" class="form-control" @bind="Reference.Email" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Phone <span class="text-danger">*</span></label>
                <input type="tel" class="form-control" @bind="Reference.Phone" />
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public ReferenceModel Reference { get; set; } = default!;
    [Parameter, EditorRequired] public int Index { get; set; }
    [Parameter] public bool CanRemove { get; set; }
    [Parameter] public EventCallback OnRemove { get; set; }
}

