@namespace sv_af5af2da9bb2403e9663a3c55eb7a148.Components.Pages.Apply
@using sv_af5af2da9bb2403e9663a3c55eb7a148.Models
@using sv_af5af2da9bb2403e9663a3c55eb7a148

<h4 class="mb-3">Personal Information</h4>

@if (!string.IsNullOrEmpty(_error))
{
    <div class="alert alert-danger">@_error</div>
}

<div class="row g-3">
    <div class="col-md-6">
        <label class="form-label">Full Name <span class="text-danger">*</span></label>
        <input type="text" class="form-control" @bind="Model.FullName" />
    </div>
    <div class="col-md-6">
        <label class="form-label">Email <span class="text-danger">*</span></label>
        <input type="email" class="form-control" @bind="Model.Email" />
    </div>
    <div class="col-md-6">
        <label class="form-label">Phone <span class="text-danger">*</span></label>
        <input type="tel" class="form-control" @bind="Model.Phone" />
    </div>
    <div class="col-md-6">
        <label class="form-label">Address <span class="text-danger">*</span></label>
        <input type="text" class="form-control" @bind="Model.Address" />
    </div>
</div>

<div class="d-flex justify-content-end mt-4">
    <button class="btn btn-primary" @onclick="HandleNext" disabled="@_validating">
        @if (_validating)
        {
            <span class="spinner-border spinner-border-sm me-1"></span>
            <span>Validating…</span>
        }
        else
        {
            <span>Next</span>
        }
    </button>
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Model { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Inject] private IApplicationService ApplicationService { get; set; } = default!;

    private string? _error;
    private bool _validating;

    private async Task HandleNext()
    {
        _error = null;

        if (!Model.IsValid())
        {
            _error = "Please fill in all required fields.";
            return;
        }

        _validating = true;
        try
        {
            var emailValid = await ApplicationService.ValidateEmailAsync(Model.Email.Trim());
            if (!emailValid)
            {
                _error = "The email address is not valid. Please check and try again.";
                return;
            }

            await OnNext.InvokeAsync();
        }
        finally
        {
            _validating = false;
        }
    }
}

@namespace sv_af5af2da9bb2403e9663a3c55eb7a148.Components.Pages.Apply
@using sv_af5af2da9bb2403e9663a3c55eb7a148.Models

<h4 class="mb-3">Work History</h4>

@if (!string.IsNullOrEmpty(_error))
{
    <div class="alert alert-danger">@_error</div>
}

@for (int i = 0; i < Entries.Count; i++)
{
    var index = i;
    <WorkEntryForm Entry="Entries[index]"
                   Index="index + 1"
                   CanRemove="Entries.Count > 1"
                   OnRemove="() => RemoveEntry(index)" />
}

<button type="button" class="btn btn-outline-primary btn-sm mb-4" @onclick="AddEntry">
    + Add Another Position
</button>

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="() => OnBack.InvokeAsync()">Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next</button>
</div>

@code {
    [Parameter, EditorRequired] public List<WorkEntryModel> Entries { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private string? _error;

    private void AddEntry() => Entries.Add(new WorkEntryModel());

    private void RemoveEntry(int index)
    {
        if (Entries.Count > 1)
            Entries.RemoveAt(index);
    }

    private async Task HandleNext()
    {
        _error = null;

        if (!Entries.All(e => e.IsValid()))
        {
            _error = "Please fill in company, title, and start date for each position.";
            return;
        }

        await OnNext.InvokeAsync();
    }
}

@namespace sv_af5af2da9bb2403e9663a3c55eb7a148.Components.Pages.Apply
@using sv_af5af2da9bb2403e9663a3c55eb7a148.Models

<h4 class="mb-3">References</h4>

@if (!string.IsNullOrEmpty(_error))
{
    <div class="alert alert-danger">@_error</div>
}

@for (int i = 0; i < References.Count; i++)
{
    var index = i;
    <ReferenceForm Reference="References[index]"
                   Index="index + 1"
                   CanRemove="References.Count > 2"
                   OnRemove="() => RemoveReference(index)" />
}

@if (References.Count < 3)
{
    <button type="button" class="btn btn-outline-primary btn-sm mb-4" @onclick="AddReference">
        + Add Reference
    </button>
}

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="() => OnBack.InvokeAsync()">Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next</button>
</div>

@code {
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private string? _error;

    private void AddReference()
    {
        if (References.Count < 3)
            References.Add(new ReferenceModel());
    }

    private void RemoveReference(int index)
    {
        if (References.Count > 2)
            References.RemoveAt(index);
    }

    private async Task HandleNext()
    {
        _error = null;

        if (!References.All(r => r.IsValid()))
        {
            _error = "Please fill in all fields for each reference.";
            return;
        }

        await OnNext.InvokeAsync();
    }
}

@namespace sv_af5af2da9bb2403e9663a3c55eb7a148.Components.Pages.Apply

<h4 class="mb-3">Cover Letter</h4>

<div class="mb-3">
    <label class="form-label">Write your cover letter</label>
    <textarea class="form-control" rows="12" maxlength="@MaxLength"
              @bind="CoverLetter" @bind:event="oninput"
              @bind:after="NotifyChanged"></textarea>
    <div class="form-text text-end">
        @(CoverLetter?.Length ?? 0) / @MaxLength characters
    </div>
</div>

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="() => OnBack.InvokeAsync()">Back</button>
