@using sv_af5af2da9bb2403e9663a3c55eb7a148

<h4 class="mb-3">Personal Information</h4>

@if (!string.IsNullOrEmpty(_error))
{
    <div class="alert alert-danger">@_error</div>
}

<div class="row g-3">
    <div class="col-md-6">
        <label class="form-label">Full Name <span class="text-danger">*</span></label>
        <input type="text" class="form-control" @bind="Model.FullName" />
    </div>
    <div class="col-md-6">
        <label class="form-label">Email <span class="text-danger">*</span></label>
        <input type="email" class="form-control" @bind="Model.Email" />
    </div>
    <div class="col-md-6">
        <label class="form-label">Phone <span class="text-danger">*</span></label>
        <input type="tel" class="form-control" @bind="Model.Phone" />
    </div>
    <div class="col-md-6">
        <label class="form-label">Address <span class="text-danger">*</span></label>
        <input type="text" class="form-control" @bind="Model.Address" />
    </div>
</div>

<div class="d-flex justify-content-end mt-4">
    <button class="btn btn-primary" @onclick="HandleNext" disabled="@_validating">
        @if (_validating)
        {
            <span class="spinner-border spinner-border-sm me-1"></span>
            <span>Validating…</span>
        }
        else
        {
            <span>Next</span>
        }
    </button>
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Model { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Inject] private IApplicationService ApplicationService { get; set; } = default!;

    private string? _error;
    private bool _validating;

    private async Task HandleNext()
    {
        _error = null;

        if (!Model.IsValid())
        {
            _error = "Please fill in all required fields.";
            return;
        }

        _validating = true;
        try
        {
            var emailValid = await ApplicationService.ValidateEmailAsync(Model.Email.Trim());
            if (!emailValid)
            {
                _error = "The email address is not valid. Please check and try again.";
                return;
            }

            await OnNext.InvokeAsync();
        }
        finally
        {
            _validating = false;
        }
    }
}

